	test('onDidChangeDiagnostics different behavior when "extensionKind" ui running on remote workspace #136955', function () {
		return runWithFakedTimers({}, async () => {

			const markerData: IMarkerData = {
				code: '666',
				startLineNumber: 1,
				startColumn: 1,
				endLineNumber: 1,
				endColumn: 1,
				severity: 1,
				source: 'me',
				message: 'message'
			};
			const target = URI.file('a');
			markerService.changeOne('bar', target, [markerData]);

			const changedData: [UriComponents, IMarkerData[]][][] = [];

			const diag = new MainThreadDiagnostics(
				new class implements IExtHostContext {
					remoteAuthority = '';
					extensionHostKind = ExtensionHostKind.LocalProcess;
					dispose() { }
					assertRegistered() { }
					set(v: any): any { return null; }
					getProxy(): any {
						return {
							$acceptMarkersChange(data: [UriComponents, IMarkerData[]][]) {
								changedData.push(data);
							}
						};
					}
					drain(): any { return null; }
				},
				markerService,
				new class extends mock<IUriIdentityService>() {
					override asCanonicalUri(uri: URI) { return uri; }
				},
				new class extends mock<IFileService>() {
					readonly onDidFilesChange = new Emitter().event;
				}
			);

			diag.$clear('bar');
			await timeout(0);
			assert.strictEqual(markerService.read().length, 0);
			assert.strictEqual(changedData.length, 1);

			diag.dispose();
		});
	});

	test('clear diagnostics on file changes', function () {
		return runWithFakedTimers({}, async () => {

			const onDidFilesChangeEmitter = new Emitter<any>();
			const markerData: IMarkerData = {
				code: '666',
				startLineNumber: 1,
				startColumn: 1,
				endLineNumber: 1,
				endColumn: 1,
				severity: 1,
				source: 'me',
				message: 'message'
			};
			const target = URI.file('a');

			const diag = new MainThreadDiagnostics(
				new class implements IExtHostContext {
					remoteAuthority = '';
					extensionHostKind = ExtensionHostKind.LocalProcess;
					dispose() { }
					assertRegistered() { }
					set(v: any): any { return null; }
					getProxy(): any {
						return {
							$acceptMarkersChange() { }
						};
					}
					drain(): any { return null; }
				},
				markerService,
				new class extends mock<IUriIdentityService>() {
					override asCanonicalUri(uri: URI) { return uri; }
				},
				new class extends mock<IFileService>() {
					readonly onDidFilesChange = onDidFilesChangeEmitter.event;
				}
			);

			// Set initial diagnostics
			diag.$changeMany('owner1', [[target, [markerData]]]);
			assert.strictEqual(markerService.read({ resource: target }).length, 1);

			// Simulate file update
			onDidFilesChangeEmitter.fire({
				rawUpdated: [target],
				rawAdded: [],
				rawDeleted: []
			});

			await timeout(0);
			assert.strictEqual(markerService.read({ resource: target }).length, 0, 'Diagnostics should be cleared after file update');

			diag.dispose();
		});
	});

	test('clear diagnostics on file deletion', function () {
