     6→import { IMarkerService, IMarkerData } from '../../../platform/markers/common/markers.js';
     7→import { URI, UriComponents } from '../../../base/common/uri.js';
     8→import { MainThreadDiagnosticsShape, MainContext, ExtHostDiagnosticsShape, ExtHostContext } from '../common/extHost.protocol.js';
     9→import { extHostNamedCustomer, IExtHostContext } from '../../services/extensions/common/extHostCustomers.js';
    10→import { IDisposable } from '../../../base/common/lifecycle.js';
    11→import { IUriIdentityService } from '../../../platform/uriIdentity/common/uriIdentity.js';
    12→import { IFileService } from '../../../platform/files/common/files.js';
    13→
    14→@extHostNamedCustomer(MainContext.MainThreadDiagnostics)
    15→export class MainThreadDiagnostics implements MainThreadDiagnosticsShape {
    16→
    17→	private readonly _activeOwners = new Set<string>();
    18→
    19→	private readonly _proxy: ExtHostDiagnosticsShape;
    20→	private readonly _markerListener: IDisposable;
    21→	private readonly _fileListener: IDisposable;
    22→
    23→	constructor(
    24→		extHostContext: IExtHostContext,
    25→		@IMarkerService private readonly _markerService: IMarkerService,
    26→		@IUriIdentityService private readonly _uriIdentService: IUriIdentityService,
    27→		@IFileService private readonly _fileService: IFileService,
    28→	) {
    29→		this._proxy = extHostContext.getProxy(ExtHostContext.ExtHostDiagnostics);
    30→
    31→		this._markerListener = this._markerService.onMarkerChanged(this._forwardMarkers, this);
    32→		this._fileListener = this._fileService.onDidFilesChange(this._onDidFilesChange, this);
    33→	}
    34→
    35→	dispose(): void {
    36→		this._markerListener.dispose();
    37→		this._fileListener.dispose();
    38→		this._activeOwners.forEach(owner => this._markerService.changeAll(owner, []));
    39→		this._activeOwners.clear();
    40→	}
    41→
    42→	private _forwardMarkers(resources: readonly URI[]): void {
    43→		const data: [UriComponents, IMarkerData[]][] = [];
    44→		for (const resource of resources) {
    45→			const allMarkerData = this._markerService.read({ resource });
    46→			if (allMarkerData.length === 0) {
    47→				data.push([resource, []]);
    48→			} else {
    49→				const forgeinMarkerData = allMarkerData.filter(marker => !this._activeOwners.has(marker.owner));
    50→				if (forgeinMarkerData.length > 0) {
    51→					data.push([resource, forgeinMarkerData]);
    52→				}
    53→			}
    54→		}
    55→		if (data.length > 0) {
    56→			this._proxy.$acceptMarkersChange(data);
    57→		}
    58→	}
    59→
    60→	private _onDidFilesChange(event: any): void {
    61→		// Clear diagnostics for updated and deleted files to allow re-analysis
    62→		const filesToClear = new Set<string>();
    63→
    64→		// Collect updated files
    65→		for (const resource of event.rawUpdated ?? []) {
    66→			filesToClear.add(this._uriIdentService.asCanonicalUri(resource).toString());
    67→		}
    68→
    69→		// Collect deleted files
    70→		for (const resource of event.rawDeleted ?? []) {
    71→			filesToClear.add(this._uriIdentService.asCanonicalUri(resource).toString());
    72→		}
    73→
    74→		// Clear diagnostics for all affected files
    75→		if (filesToClear.size > 0) {
    76→			const owners = new Set<string>();
    77→			for (const uriStr of filesToClear) {
